function mergeTranslations(base: TranslationMap, overrides: TranslationMap): TranslationMap {
  const merged: TranslationMap = { ...base };
  for (const [key, value] of Object.entries(overrides)) {
    const current = merged[key];
    merged[key] =
      typeof value === "string" || typeof current === "string" || current === undefined
        ? value
        : mergeTranslations(current, value);
  }
  return merged;
}

export const ru: TranslationMap = mergeTranslations(en, ruOverrides);
